<?php
namespace App\Http\Controllers;
use App\Models\Project; use App\Support\ProjectAccess; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB;
class ProjectReflectionController extends Controller {
 public static function defaultFields(): array { return [['key'=>'experience','label'=>'Pengalaman selama project','type'=>'textarea'],['key'=>'goal','label'=>'Apakah tujuan project tercapai?','type'=>'radio','options'=>['Sangat','Ya','Sebagian','Tidak']],['key'=>'reason','label'=>'Alasan','type'=>'textarea'],['key'=>'good','label'=>'Hal yang berjalan baik','type'=>'textarea'],['key'=>'obstacles','label'=>'Kendala','type'=>'textarea'],['key'=>'improve','label'=>'Apa yang perlu diperbaiki','type'=>'textarea'],['key'=>'lesson','label'=>'Lesson Learned','type'=>'textarea']]; }
 public function save(Request $r,int $id) { $p=Project::findOrFail($id); abort_unless(ProjectAccess::userCanAccess((int)Auth::id(),$p),403); abort_unless(DB::table('project_evaluations')->where('project_id',$id)->where('publication_status','published')->exists(),403); $r->validate(['answers'=>'required|array','action'=>'required|in:draft,submitted']); DB::table('project_reflections')->updateOrInsert(['project_id'=>$id,'student_id'=>Auth::id()],['answers'=>json_encode($r->answers),'status'=>$r->action,'submitted_at'=>$r->action==='submitted'?now():null,'updated_at'=>now(),'created_at'=>now()]); return back()->with('success',$r->action==='submitted'?'Refleksi berhasil dikirim.':'Draft refleksi disimpan.'); }
 public function configure(Request $r,int $id) { $p=Project::findOrFail($id); abort_unless(Auth::user()?->role==='lecturer'&&ProjectAccess::lecturerCanView(Auth::user(),$p),403); $d=$r->validate(['fields'=>'required|array']); DB::table('project_reflection_forms')->updateOrInsert(['project_id'=>$id],['fields'=>json_encode($d['fields']),'updated_by'=>Auth::id(),'updated_at'=>now(),'created_at'=>now()]); return back()->with('success','Form refleksi diperbarui.'); }
}
